DROP TABLE IF EXISTS micro_niches CASCADE;
DROP TABLE IF EXISTS sub_niches CASCADE;
DROP TABLE IF EXISTS niches CASCADE;
DROP TABLE IF EXISTS macro_niches CASCADE;

CREATE TABLE macro_niches (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  slug TEXT UNIQUE NOT NULL,
  name TEXT NOT NULL,
  description TEXT,
  icon TEXT,
  created_at TIMESTAMPTZ DEFAULT NOW()
);

CREATE TABLE niches (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  slug TEXT UNIQUE NOT NULL,
  name TEXT NOT NULL,
  macro_id UUID REFERENCES macro_niches(id) ON DELETE CASCADE,
  description TEXT,
  created_at TIMESTAMPTZ DEFAULT NOW()
);

CREATE TABLE sub_niches (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  slug TEXT UNIQUE NOT NULL,
  name TEXT NOT NULL,
  niche_id UUID REFERENCES niches(id) ON DELETE CASCADE,
  macro_id UUID REFERENCES macro_niches(id) ON DELETE CASCADE,
  description TEXT,
  created_at TIMESTAMPTZ DEFAULT NOW()
);

CREATE TABLE micro_niches (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  slug TEXT UNIQUE NOT NULL,
  name TEXT NOT NULL,
  sub_niche_id UUID REFERENCES sub_niches(id) ON DELETE CASCADE,
  niche_id UUID REFERENCES niches(id) ON DELETE CASCADE,
  macro_id UUID REFERENCES macro_niches(id) ON DELETE CASCADE,
  seed_keyword TEXT,
  created_at TIMESTAMPTZ DEFAULT NOW()
);

ALTER TABLE macro_niches ENABLE ROW LEVEL SECURITY;
ALTER TABLE niches ENABLE ROW LEVEL SECURITY;
ALTER TABLE sub_niches ENABLE ROW LEVEL SECURITY;
ALTER TABLE micro_niches ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Public read macro_niches taxonomy" ON macro_niches FOR SELECT USING (true);
CREATE POLICY "Public read niches taxonomy" ON niches FOR SELECT USING (true);
CREATE POLICY "Public read sub_niches taxonomy" ON sub_niches FOR SELECT USING (true);
CREATE POLICY "Public read micro_niches taxonomy" ON micro_niches FOR SELECT USING (true);





CREATE INDEX IF NOT EXISTS idx_niches_macro_id ON niches(macro_id);
CREATE INDEX IF NOT EXISTS idx_sub_niches_niche_id ON sub_niches(niche_id);
CREATE INDEX IF NOT EXISTS idx_sub_niches_macro_id ON sub_niches(macro_id);
CREATE INDEX IF NOT EXISTS idx_micro_niches_sub_niche_id ON micro_niches(sub_niche_id);
CREATE INDEX IF NOT EXISTS idx_micro_niches_seed_keyword ON micro_niches(seed_keyword);